  cleaned = '62' + cleaned.substring(1);
}

// Jika diawali 62 → biarkan
// Jika format lain → tetap pakai hasil cleaned

return [
  {
    json: {
      phone: cleaned
    }
  }
];

const ts = $input.first().json.body.call.start_timestamp;

// Convert ke WIB
const d = new Date(
  new Date(ts).toLocaleString('en-US', { timeZone: 'Asia/Jakarta' })
);

const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

const formatted =
  `${String(d.getDate()).padStart(2,'0')}-` +
  `${months[d.getMonth()]}-` +
  `${String(d.getFullYear()).slice(-2)} ` +
  `${String(d.getHours()).padStart(2,'0')}:` +
  `${String(d.getMinutes()).padStart(2,'0')}`;

return [
  {
    json: {
      start_datetime: formatted
    }
  }
];

const toNumber = $('Webhook').first().json.body.call.to_number || "";

// Remove '+' at the start if it exists
const cleanedNumber = toNumber.replace(/^\+/, "");

return [
  {
    json: {
      originalNumber: toNumber,
      cleanedNumber: cleanedNumber
    }
