// --- CONFIGURATION ---
// Pastikan nama property sesuai output node sebelumnya (biasanya 'data')
const inputRaw = items[0].json.data;

// --- 1. SAFETY CHECK: Cek apakah ada data? ---
if (!inputRaw || typeof inputRaw !== 'string') {
    // Jika data kosong, kembalikan array kosong biar workflow GAK ERROR merah, tapi berhenti baik-baik.
    return [];
}

// --- 2. PARSING FUNCTION (Robust CSV Parser) ---
function parseCSV(str) {
    const arr = [];
    let quote = false; 
    let col = 0, row = 0;

    for (let c = 0; c < str.length; c++) {
        let cc = str[c], nc = str[c+1];
        arr[row] = arr[row] || []; 
        arr[row][col] = arr[row][col] || '';

        // Handle Double Quotes (kutip dua kali dianggap satu kutip teks)
        if (cc == '"' && quote && nc == '"') { arr[row][col] += cc; ++c; continue; }

        // Handle Pembuka/Penutup Kutip
        if (cc == '"') { quote = !quote; continue; }

        // Handle Koma (Pemisah) - Cuma aktif kalau GAK lagi dikutip
        if (cc == ',' && !quote) { ++col; continue; }

        // Handle Enter (Baris Baru) - Cuma aktif kalau GAK lagi dikutip
        if (cc == '\r' && nc == '\n' && !quote) { ++row; col = 0; ++c; continue; }
        if (cc == '\n' && !quote) { ++row; col = 0; continue; }
        if (cc == '\r' && !quote) { ++row; col = 0; continue; }

        // Masukkan karakter
        arr[row][col] += cc;
    }
    return arr;
}

try {
    const parsedData = parseCSV(inputRaw);

    // --- 3. HEADER CLEANING ---
    // Membersihkan header dari spasi atau karakter aneh (BOM) di awal file
    if (parsedData.length === 0) return [];

    const headers = parsedData[0].map(h => h.trim().replace(/^[\uFEFF\xEF\xBB\xBF]*/, ""));

    const result = [];

    // Loop data mulai index 1
    for (let i = 1; i < parsedData.length; i++) {
        const currentLine = parsedData[i];

        // Skip baris kosong/rusak
        if (currentLine.length < headers.length && !currentLine[0]) continue;

        const row = {};
        headers.forEach((header, index) => {
            // Mapping Header -> Value
            // Membersihkan value dari spasi berlebih di awal/akhir (opsional, aman dihapus .trim() nya kalau butuh spasi asli)
            let value = currentLine[index] ?? "";
            row[header] = value; 
        });

        result.push({ json: row });
    }

    return result;

} catch (error) {
    // --- 4. ERROR REPORTING ---
    // Jika script error, dia akan melempar pesan jelas, bukan crash aneh
    throw new Error(`Gagal parsing CSV: ${error.message}`);
}

const days = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
const months = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];

const today = new Date();
// PENTING: Pastikan Timezone n8n sesuai (misal Asia/Jakarta) atau gunakan offset jika perlu.
// Kode ini menggunakan waktu server n8n.

// Helper function untuk format tanggal
function formatDate(dateObj, isToday = false, isTomorrow = false) {
  const dayName = days[dateObj.getDay()];
  const dateStr = `${dateObj.getDate()} ${months[dateObj.getMonth()]} ${dateObj.getFullYear()}`;
  let suffix = "";
  if (isToday) suffix = " (Hari Ini)";
  else if (isTomorrow) suffix = " (Besok)";

  return `- ${dayName}, ${dateStr}${suffix}`;
}

let section1 = []; // Minggu Ini
let section2 = []; // Minggu Depan
let section3 = []; // 2 Minggu Lagi

// Clone tanggal hari ini untuk iterasi agar 'today' asli tidak berubah
let currentCursor = new Date(today);

// 1. ISI MINGGU INI (Dari hari ini sampai ketemu hari Minggu)
// Loop maksimal 7 kali untuk keamanan, berhenti saat ketemu Minggu
for (let i = 0; i < 7; i++) {
  // Cek apakah hari ini atau besok untuk suffix
  const isToday = currentCursor.getDate() === today.getDate() && currentCursor.getMonth() === today.getMonth();
  const tomorrow = new Date(today);
  tomorrow.setDate(today.getDate() + 1);
  const isTomorrow = currentCursor.getDate() === tomorrow.getDate() && currentCursor.getMonth() === tomorrow.getMonth();

  section1.push(formatDate(currentCursor, isToday, isTomorrow));

  // Jika hari ini adalah Minggu (0), berhenti loop setelah memasukkannya
  if (currentCursor.getDay() === 0) {
    break;
  }
  // Maju 1 hari
  currentCursor.setDate(currentCursor.getDate() + 1);
}

// Maju 1 hari lagi agar start dari SENIN untuk minggu depan
currentCursor.setDate(currentCursor.getDate() + 1);

// 2. ISI MINGGU DEPAN (7 Hari: Senin - Minggu)
for (let i = 0; i < 7; i++) {
  section2.push(formatDate(currentCursor));
  currentCursor.setDate(currentCursor.getDate() + 1);
}

// 3. ISI 2 MINGGU LAGI (7 Hari: Senin - Minggu)
for (let i = 0; i < 7; i++) {
  section3.push(formatDate(currentCursor));
  currentCursor.setDate(currentCursor.getDate() + 1);
}

// Gabungkan string dengan Header
let finalCalendar = "";

finalCalendar += "🗓️ **MINGGU INI**\n" + section1.join("\n") + "\n\n";
finalCalendar += "🗓️ **MINGGU DEPAN**\n" + section2.join("\n") + "\n\n";
finalCalendar += "🗓️ **2 MINGGU LAGI**\n" + section3.join("\n");

return {
  calendar_context: finalCalendar,
  current_day: days[today.getDay()],
  current_date: `${today.getDate()} ${months[today.getMonth()]} ${today.getFullYear()}`
};

